SET NAMES utf8mb4;

START TRANSACTION;

ALTER TABLE menu_categories ADD COLUMN IF NOT EXISTS description TEXT NULL;
ALTER TABLE menu_items ADD COLUMN IF NOT EXISTS image_url VARCHAR(500) NULL;

DELETE mi
FROM menu_items mi
JOIN menu_categories mc ON mc.id = mi.category_id
WHERE mc.type = 'catering'
  AND mc.name IN ('FOOD TRAYS', 'FROZEN READY TO EAT MEALS');

DELETE FROM menu_categories
WHERE type = 'catering'
  AND name IN ('FOOD TRAYS', 'FROZEN READY TO EAT MEALS');

  'MEDIUM BILAO PLATTER - 5-8 PAX PER ORDER', '\n',
