(@cat_food_trays, 'BILAO PLATTER', 'Baked mussels, pork adobo, fried chicken, buttered shrimps, steamed veggies, grilled liempo, daing na bangus, salted egg, ensaladang talong, mangga''t alamang', 1700.00, NULL, 1),
